export default FormWidget

import isEmpty from 'lodash/isEmpty'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'
import { getQueryFilter } from './filter-utils'

/**
 * 在 tableSchema 中查找 value?.relate?.id 等于 tableID 的对应 key
 */
export const findRelateKeyInTableSchema = (tableSchema: any, tableID: string): string | null => {
  if (!tableSchema || !tableSchema.properties) {
    return null
  }

  for (const [key, property] of Object.entries(tableSchema.properties)) {
    if ((property as any)?.relate?.id === tableID) {
      return key
    }
  }

  return null
}

/**
 * 在树形数据中查找节点
 */
export const findTreeNode = (treeData: any[], value: any): any => {
  for (const node of treeData) {
    if (node.value === value) {
      return node
    }
    if (node.children && node.children.length > 0) {
      const found = findTreeNode(node.children, value)
      if (found) return found
    }
  }
  return null
}

/**
 * 替换字段占位符
 * 将 [field]:fieldName 或 [field][table]:fieldName 替换为实际值
 */
export const replaceFieldPlaceholders = (value: any, allValues: Record<string, any>): any => {
  if (typeof value === 'string') {
    // 处理 [field]:fieldName 占位符
    if (value.startsWith('[field]:')) {
      const key = value.substring(8)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    // 处理 [field][table]:fieldName 占位符
    if (value.startsWith('[field][table]:')) {
      const key = value.substring(15)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    return value
  }

  if (isArray(value)) {
    return value.map(item => replaceFieldPlaceholders(item, allValues))
  }

  if (isObject(value) && value !== null) {
    const result: Record<string, any> = {}
    for (const [key, val] of Object.entries(value)) {
      result[key] = replaceFieldPlaceholders(val, allValues)
    }
    return result
  }

  return value
}

/**
 * 处理过滤器
 * 将内置查询过滤器应用到 filterObj 中
 *
 * @param filterObj - 过滤器对象，会被修改
 * @param field - 字段配置
 * @param getFormState - 获取表单状态的函数
 * @param outTable - 外部表的 editingSchema（可选）
 */
export const dealFilter = (
  filterObj: Record<string, any>,
  field: any,
  getFormState?: () => any,
  outTable?: { editingSchema?: Record<string, any> }
) => {
  // 在过滤器中，如果没有设置 field.filter，则使用内置查询
  const ifFilter = field.filter

  // 设置了内置查询
  if (field.insideFilter && !ifFilter) {
    const inFilter = getQueryFilter(field.insideFilter, field.schema)
    const allValues = {
      ...(outTable?.editingSchema || {}),
      ...(getFormState?.()?.values || {})
    }

    // 确保 filterObj 有 search 属性
    if (!filterObj.search) {
      filterObj.search = {}
    }

    // 替换占位符并添加到搜索条件中
    for (const key in inFilter) {
      let insideVal = inFilter[key]
      const replacedVal = replaceFieldPlaceholders(insideVal, allValues)
      filterObj.search[key] = replacedVal
    }
  }
}

/**
 * 简单的 fieldRender 函数
 * 用于在列表中显示字段值
 */
export const fieldRender = (value: any, _schema?: any): React.ReactNode => {
  // 字符串、数字、布尔值直接显示
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return value
  }

  // 对象显示 .name
  if (isObject(value) && !isArray(value)) {
    return (value as any).name ?? (value as any).id ?? JSON.stringify(value)
  }

  // 数组显示 .name join(',')
  if (isArray(value)) {
    return value
      .map(item => {
        if (typeof item === 'string' || typeof item === 'number') {
          return item
        }
        if (isObject(item)) {
          return (item as any).name ?? (item as any).id
        }
        return JSON.stringify(item)
      })
      .filter(Boolean)
      .join(',')
  }

  // 空值处理
  if (isEmpty(value)) {
    return null
  }

  return JSON.stringify(value)
}

/**
 * 获取表单状态 - 用于获取其他字段的值
 * 类似于 use('form') 的功能
 */
export const getFormState = (formState: any, currentFieldKey?: string) => {
  // TODO: 实现表单状态获取逻辑
  // 这个函数应该从 form state 中获取其他字段的值
  // 用于字段联动和脚本计算
  if (!formState) {
    return {}
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    // 跳过当前字段，避免循环依赖
    if (key !== currentFieldKey) {
      values[key] = formState.values[key]
    }
  }

  return { values }
}

/**
 * 获取表单所有值 - 用于字段脚本
 */
export const getFormValues = (schema: any, formState?: any) => {
  if (!formState) {
    return null
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    if (key !== schema.key) {
      values[key] = formState.values[key]
    }
  }

  return values
}

/**
 * Schema 转换器
 * 将关联字段的 schema 转换为组件可用的格式
 */
export const schemaConverter = (
  schema: any,
  options?: { tableSchema?: any }
): {
  type: string
  schema: { name: string }
  fieldSchema?: any
  relateSchema: any
  tableID: string
  displayField: string
  relateTableName: string
  insideFilter?: any
  relateShowFields?: any[]
  selectType?: 'single' | 'multiple'
  key?: string
} | null => {
  if (
    !['object', 'array'].includes(schema.type) ||
    !schema.relate?.id ||
    schema.recordSelectType
  ) {
    return null
  }

  const relate = schema.relate
  const relateShowFields = schema.relateShowFields
  const id = relate.id
  const fieldSchema = relate.fields?.[0]?.fieldSchema

  const result: any = {
    type: schema.selectType === 'multiple' ? 'relate_multi_select' : 'relate_fkselect',
    schema: { name: `core/t/${id}/d` },
    fieldSchema,
    relateSchema: schema,
    tableID: id,
    displayField: relate.fields?.[0]?.key || 'name',
    relateTableName: id,
    insideFilter: schema.insideFilter,
  }

  // 使用 findRelateKeyInTableSchema 查找关联键
  if (options?.tableSchema) {
    const relateKey = findRelateKeyInTableSchema(options.tableSchema, relate.id)
    if (relateKey) {
      result.key = relateKey
    }
  }

  // 多字段
  if (relateShowFields && relateShowFields.length > 0) {
    result.type = 'relate_list_fkselect'
    result.relateShowFields = relateShowFields
    result.selectType = schema.selectType
  }

  return result
}

import React, { useState, useEffect, forwardRef } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { DropdownMenu, DropdownMenuContent, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandSeparator } from '@/components/ui/command';
import { Checkbox } from '@/components/ui/checkbox';
import { Check, ChevronsUpDown, X, FolderPlus, Folder, ArrowLeft } from 'lucide-react';
import { loadPCAData } from './pca';

// ====================== 核心类型定义 ======================
/** 省市区数据结构类型 */
interface PCAItem {
  label: string;
  value: string;
  children?: PCAItem[];
}

/** Form Area 配置类型 */
export interface FormAreaConfig {
  /**
   * 区域类型：p=省 | pc=省市 | pca=省市区
   */
  areaType?: 'p' | 'pc' | 'pca';
  /**
   * 是否多选
   */
  multiple?: boolean;
  /**
   * 尺寸
   */
  size?: 'sm' | 'md' | 'lg';
  /**
   * 是否禁用
   */
  disabled?: boolean;
}

/** Form Area Props 类型 */
export interface FormAreaProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'> {
  /**
   * 当前值（多选时为数组）
   */
  value?: string | string[];
  /**
   * 默认值
   */
  defaultValue?: string | string[];
  /**
   * 配置项
   */
  config?: FormAreaConfig;
  /**
   * 值变化回调
   */
  onChange?: (value: string | string[]) => void;
  /**
   * 单元格键值
   */
  cellKey?: string;
}

// ====================== 工具函数（带类型注解） ======================
/** 处理单选级联数据格式 */
const getData = (areaType: 'p' | 'pc' | 'pca', pcaData: PCAItem[]): { value: string; label: string; children?: any[] }[] => {
  if (areaType === 'p') {
    return pcaData.map(item => ({ value: item.label, label: item.label }));
  } else if (areaType === 'pc') {
    return pcaData.map(item => ({
      value: item.label,
      label: item.label,
      children: item.children?.map(child => ({ value: child.label, label: child.label })) || [],
    }));
  } else {
    return pcaData.map(item => ({
      value: item.label,
      label: item.label,
      children: item.children?.map(child => ({
        value: child.label,
        label: child.label,
        children: child.children?.map(grand => ({ value: grand.label, label: grand.label })) || [],
      })) || [],
    }));
  }
};

/** 转换为多选格式的数组 */
const convertToMultipleFormat = (value: unknown): string[] => {
  if (!value) return [];
  if (Array.isArray(value)) return value as string[];
  return [String(value)];
};

/** 生成层级选择数据（适配 Command 递归渲染） */
const getHierarchyData = (areaType: 'p' | 'pc' | 'pca', pcaData: PCAItem[]): any[] => {
  const buildItem = (item: PCAItem, parentPath = '') => {
    const currentPath = parentPath ? `${parentPath}/${item.label}` : item.label;
    const result = {
      value: currentPath,
      label: item.label,
      key: currentPath,
      parentPath,
      hasChildren: !!item.children?.length,
      children: [] as any[],
    };

    // 根据 areaType 控制层级
    const isProvinceLevel = !parentPath;
    const isCityLevel = parentPath && !parentPath.includes('/');

    if (areaType === 'p' && isProvinceLevel) {
      // 仅省级
      return result;
    } else if (areaType === 'pc' && (isProvinceLevel || isCityLevel)) {
      // 省+市级
      result.children = item.children?.map(child => buildItem(child, currentPath)) || [];
      return result;
    } else if (areaType === 'pca') {
      // 省+市+区
      result.children = item.children?.map(child => buildItem(child, currentPath)) || [];
      return result;
    }
    return null;
  };

  return pcaData.map(item => buildItem(item)).filter(Boolean) as any[];
};

/** 处理旧数据格式（-分隔转/分隔） */
const dealOldData = (v: string | undefined, pcaData: PCAItem[]): string | undefined => {
  if (!v) return undefined;
  const list = v.split('-');
  if (list.length === 0) return v;

  const result: string[] = [];
  const province = pcaData.find(p => p.value === list[0]);
  if (province) {
    result.push(province.label);
    const city = province.children?.find(c => c.value === list[1]);
    if (city) {
      result.push(city.label);
      const district = city.children?.find(d => d.value === list[2]);
      if (district) {
        result.push(district.label);
      }
    }
  }
  return result.length > 0 ? result.join('/') : v;
};

// ====================== 核心组件 ======================
const FormArea = forwardRef<HTMLDivElement, FormAreaProps>(
  (
    {
      className,
      value: controlledValue,
      defaultValue,
      config = {},
      onChange
    }
  ) => {
    const { areaType = 'pca', multiple = false, disabled = false } = config;

    // 状态管理
    const [internalValue, setInternalValue] = useState<string | string[]>(
      multiple && Array.isArray(defaultValue) ? defaultValue : (defaultValue as string || '')
    );
    const [pcaData, setPcaData] = useState<PCAItem[]>([]);
    const [selectedValues, setSelectedValues] = useState<string[]>([]); // 多选选中值
    const [open, setOpen] = useState(false); // 下拉面板开关
    const [expandedKeys, setExpandedKeys] = useState<string[]>([]); // 展开的层级key

    // 单选级联核心状态
    const [currentLevel, setCurrentLevel] = useState(0); // 当前级联层级（0=省、1=市、2=区）
    const [selectedPath, setSelectedPath] = useState<string[]>([]); // 单选选中的路径（如 ['浙江省', '杭州市']）

    const isControlled = controlledValue !== undefined;
    const value = isControlled ? controlledValue : internalValue;

    // 加载省市区数据
    useEffect(() => {
      loadPCAData().then((res: PCAItem[]) => {
        setPcaData(res);
        // 初始化多选选中值
        if (multiple) {
          setSelectedValues(convertToMultipleFormat(value));
        }
        // 初始化单选选中路径
        if (!multiple) {
          const rawValue = value as string;
          const displayValue = dealOldData(rawValue, res) || '';
          const path = displayValue.split('/').filter(Boolean);
          setSelectedPath(path);
          setCurrentLevel(path.length > 0 ? path.length - 1 : 0);
        }
      });
    }, [value, multiple]);

    // 切换层级展开/折叠
    const toggleExpand = (key: string) => {
      setExpandedKeys(prev =>
        prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
      );
    };

    // 获取当前层级的数据源
    const getCurrentLevelData = (): any[] => {
      if (currentLevel === 0) {
        return getData(areaType, pcaData);
      }
      // 根据选中路径查找下一级数据
      let currentData = getData(areaType, pcaData);
      for (let i = 0; i < currentLevel; i++) {
        const target = currentData.find(item => item.value === selectedPath[i]);
        if (!target || !target.children) {
          return [];
        }
        currentData = target.children;
      }
      return currentData;
    };

    // 返回上一级
    const handleBack = () => {
      if (currentLevel > 0) {
        setCurrentLevel(prev => prev - 1);
        setSelectedPath(prev => prev.slice(0, currentLevel - 1));
      }
    };

    // 处理值变化
    const handleValueChange = (newValue: string | string[]) => {
      if (!isControlled) {
        setInternalValue(newValue);
      }
      onChange?.(newValue);
    };

    // ====================== 单选级联逻辑 ======================
    const renderSingleSelect = () => {
      const rawValue = value as string;
      const displayValue = dealOldData(rawValue, pcaData) || '';
      // 当前层级的数据源
      const currentData = getCurrentLevelData();
      // 当前层级的选中值
      const currentValue = selectedPath[currentLevel];

      // 级联选择变更处理
      const handleSelect = (itemValue: string) => {
        // 新的选中路径
        const newSelectedPath = [...selectedPath.slice(0, currentLevel), itemValue];
        setSelectedPath(newSelectedPath);

        // 判断是否是最后一级
        const maxLevel = areaType === 'p' ? 0 : areaType === 'pc' ? 1 : 2;
        const isLastLevel = currentLevel >= maxLevel;

        if (isLastLevel) {
          // 最后一级：触发onChange并关闭下拉
          const finalValue = newSelectedPath.join('/');
          handleValueChange(finalValue);
          setOpen(false);
          // 重置层级（下次打开从第一级开始）
          setCurrentLevel(0);
        } else {
          // 非最后一级：切换到下一级
          setCurrentLevel(prev => prev + 1);
        }
      };

      return (
        <DropdownMenu open={open} onOpenChange={setOpen}>
          <DropdownMenuTrigger asChild>
            <Button
              variant="outline"
              disabled={disabled}
              className={cn("w-full justify-between", className)}
            >
              {displayValue || "请选择"}
              <ChevronsUpDown className="h-4 w-4 ml-2 shrink-0" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className="w-70 p-0">
            <Command className="h-75 overflow-auto">
              <CommandInput placeholder={"请选择区域"} disabled={disabled} />
              <CommandEmpty>未找到匹配项</CommandEmpty>

              {/* 返回上一级按钮 */}
              {currentLevel > 0 && (
                <>
                  <CommandItem
                    key="back"
                    onSelect={handleBack}
                    disabled={disabled}
                    className="flex items-center gap-2"
                  >
                    <ArrowLeft className="h-4 w-4" />
                    <span>{"返回上一级"}</span>
                  </CommandItem>
                  <CommandSeparator />
                </>
              )}

              {/* 渲染当前层级的选项 */}
              <CommandGroup>
                {currentData.map((item) => (
                  <CommandItem
                    key={item.value}
                    value={item.value}
                    disabled={disabled}
                    onSelect={() => handleSelect(item.value)}
                  >
                    <Check
                      className={cn(
                        "mr-2 h-4 w-4",
                        item.value === currentValue ? "opacity-100" : "opacity-0"
                      )}
                    />
                    {item.label}
                  </CommandItem>
                ))}
              </CommandGroup>
            </Command>
          </DropdownMenuContent>
        </DropdownMenu>
      );
    };

    // ====================== 多选层级逻辑 ======================
    const renderMultipleSelect = () => {
      const hierarchyData = getHierarchyData(areaType, pcaData);

      // 处理选中状态变更
      const handleCheck = (key: string) => {
        const newSelected = selectedValues.includes(key)
          ? selectedValues.filter(item => item !== key)
          : [...selectedValues, key];
        setSelectedValues(newSelected);
        handleValueChange(newSelected);
      };

      // 清空所有选中项
      const handleClearAll = () => {
        setSelectedValues([]);
        handleValueChange([]);
      };

      // 递归渲染层级选项（模拟树形结构）
      const renderHierarchyItems = (items: any[], depth = 0) => {
        return items.map(item => (
          <div key={item.key} className={cn(`pl-${depth * 16}px`, "py-1")}>
            <div className="flex items-center gap-1">
              {/* 展开/折叠按钮 */}
              {item.hasChildren && (
                <button
                  type="button"
                  onClick={() => toggleExpand(item.key)}
                  disabled={disabled}
                  className="h-4 w-4 flex items-center justify-center text-gray-500"
                >
                  {expandedKeys.includes(item.key) ? (
                    <FolderPlus className="h-3 w-3" />
                  ) : (
                    <Folder className="h-3 w-3" />
                  )}
                </button>
              )}
              {/* 无子集时补位，保持对齐 */}
              {!item.hasChildren && <span className="h-4 w-4"></span>}

              {/* 复选框 + 标签 */}
              <Checkbox
                checked={selectedValues.includes(item.key)}
                onCheckedChange={() => handleCheck(item.key)}
                disabled={disabled}
                className="mr-2"
              />
              <span
                className={cn(
                  "text-sm cursor-pointer",
                  disabled && "text-gray-400 cursor-not-allowed"
                )}
                onClick={() => !disabled && handleCheck(item.key)}
              >
                {item.label}
              </span>
            </div>

            {/* 渲染子级（展开状态下） */}
            {item.hasChildren && expandedKeys.includes(item.key) && (
              <div className="mt-1">
                {renderHierarchyItems(item.children, depth + 1)}
              </div>
            )}
          </div>
        ));
      };

      return (
        <div className={cn("border rounded-md p-2", {
          'opacity-50 cursor-not-allowed': disabled,
          'border-gray-200': !disabled,
        })}>
          {/* 选中项标签 */}
          <div className="flex flex-wrap gap-2 mb-2">
            {selectedValues.map((value) => (
              <div key={value} className="flex items-center gap-1 bg-gray-100 px-2 py-1 rounded">
                <span className="text-sm">{value.split('/').pop()}</span>
                <button
                  type="button"
                  onClick={() => handleCheck(value)}
                  disabled={disabled}
                  className="h-4 w-4 rounded-full hover:bg-gray-200 flex items-center justify-center"
                >
                  <X className="h-3 w-3" />
                </button>
              </div>
            ))}
            {selectedValues.length > 0 && (
              <button
                type="button"
                onClick={handleClearAll}
                disabled={disabled}
                className="text-sm text-gray-500 hover:text-gray-700"
              >
                清空
              </button>
            )}
          </div>

          {/* 层级选择区域（模拟树形） */}
          <div className="max-h-75 overflow-auto pr-2">
            {renderHierarchyItems(hierarchyData)}
          </div>
        </div>
      );
    };

    // 根据多选/单选渲染不同组件
    return multiple ? renderMultipleSelect() : renderSingleSelect();
  }
);

FormArea.displayName = "FormArea";

export default FormArea
export { FormArea }
